import * as React from 'react';
import { Link } from 'gatsby';
import Seo from '@src/components/seo';

const UsingSSR = ({ serverData } : any) => (
  <div>
    <h2 className="mainColor">
      Using SSR
    </h2>
    <h1>
      This page is
      {' '}
      <b>rendered server-side</b>
    </h1>
    <p>
      This page is rendered server side every time the page is requested.
      Reload it to see a(nother) random photo from
      {' '}
      <code>dog.ceo/api/breed/shiba/images/random</code>
      :
    </p>
    <img
      style={{ width: '320px', borderRadius: 'var(--border-radius)' }}
      alt="A random dog"
      src={serverData.message}
    />
    <p>
      To learn more, head over to our
      {' '}
      <a href="https://www.gatsbyjs.com/docs/reference/rendering-options/server-side-rendering/">
        documentation about Server Side Rendering
      </a>
      .
    </p>
    <Link to="/">Go back to the homepage</Link>
  </div>
);

export const Head = () => (
  <Seo
    title="Using SSR"
    description="Gatsby SSR starter sample page."
    pathname="/using-ssr"
    noIndex
  />
);

export default UsingSSR;

export async function getServerData() {
  try {
    const res = await fetch('https://dog.ceo/api/breed/shiba/images/random');
    if (!res.ok) {
      throw new Error('Response failed');
    }
    return {
      props: await res.json(),
    };
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  } catch (error) {
    return {
      status: 500,
      headers: {},
      props: {},
    };
  }
}
